+function extractStdout(output: unknown): string | undefined {
+  if (typeof output === "string") {
+    return output;
+  }
+  if (output && typeof output === "object") {
+    const record = output as Record<string, unknown>;
+    const stdout = asString(record.stdout);
+    if (stdout) {
+      return stdout;
+    }
+  }
+  return undefined;
+}
