+function parseRgArgs(args: string[], cwd: string | null): { input: Record<string, unknown> } | null {
+  if (args.length < 2) {
+    return null;
+  }
+
+  const input: Record<string, unknown> = {};
+  let pattern: string | null = null;
+  let pathArg: string | null = null;
+
+  for (let i = 1; i < args.length; i += 1) {
+    const arg = args[i];
+
+    if (arg === "--") {
+      continue;
+    }
+
+    if (arg.startsWith("-")) {
+      switch (arg) {
+        case "-i":
+          input["-i"] = true;
+          break;
+        case "-U":
+          input.multiline = true;
+          break;
+        case "-A":
+        case "-B":
+        case "-C": {
+          const value = args[i + 1];
+          if (value) {
+            input[arg] = value;
+            i += 1;
+          }
+          break;
+        }
+        case "-l":
+        case "--files-with-matches":
+          input.output_mode = "files_with_matches";
+          break;
+        case "-c":
+        case "--count":
+          input.output_mode = "count";
+          break;
+        case "-g":
+        case "--glob": {
+          const value = args[i + 1];
+          if (value) {
+            input.glob = value;
+            i += 1;
+          }
+          break;
+        }
+        case "-t":
+        case "--type": {
+          const value = args[i + 1];
+          if (value) {
+            input.type = value;
+            i += 1;
+          }
+          break;
+        }
+        case "-e":
+        case "--regexp": {
+          const value = args[i + 1];
+          if (value) {
+            pattern = value;
+            i += 1;
+          }
+          break;
+        }
+        default:
+          break;
+      }
+      continue;
+    }
+
+    if (!pattern) {
+      pattern = arg;
+      continue;
+    }
+
+    if (!pathArg) {
+      pathArg = arg;
+      continue;
+    }
+  }
+
+  if (!pattern) {
