+  }
+
+  input.pattern = pattern;
+  if (pathArg) {
+    input.path = cwd ? relativizePath(pathArg, cwd) : pathArg;
+  }
+
+  return { input };
+}
+
+function parseSedArgs(args: string[], cwd: string | null): { filePath: string; startLine: number } | null {
+  const nIndex = args.indexOf("-n");
+  if (nIndex === -1) {
