+  }
+
+  const startLine = parseInt(rangeMatch[1], 10);
+  if (!Number.isFinite(startLine) || startLine <= 0) {
+    return null;
+  }
+
+  const filePath = cwd ? relativizePath(fileArg, cwd) : fileArg;
+
+  return { filePath, startLine };
